#include <stdio.h>
#include <stdlib.h>

// Structure for an adjacency list node
typedef struct AdjListNode {
    int vertex;
    struct AdjListNode* next;
} AdjListNode;

// Structure for a graph
typedef struct Graph {
    int numVertices;
    AdjListNode** adjLists;
} Graph;

// Function to create a new adjacency list node
AdjListNode* createNode(int vertex) {
    AdjListNode* newNode = (AdjListNode*) malloc(sizeof(AdjListNode));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->vertex = vertex;
    newNode->next = NULL;
    return newNode;
}

// Function to create a graph with given number of vertices
Graph* createGraph(int vertices) {
    Graph* graph = (Graph*) malloc(sizeof(Graph));
    if (!graph) {
        printf("Memory error\n");
        return NULL;
    }

    graph->numVertices = vertices;

    // Create an array to hold the adjacency lists
    graph->adjLists = (AdjListNode**) malloc(vertices * sizeof(AdjListNode*));
    for (int i = 0; i < vertices; i++) {
        graph->adjLists[i] = NULL;
    }

    return graph;
}

// Function to add an edge to the graph
void addEdge(Graph* graph, int src, int dest) {
    // Add an edge from src to dest
    AdjListNode* newNode = createNode(dest);
    newNode->next = graph->adjLists[src];
    graph->adjLists[src] = newNode;

    // Add an edge from dest to src (for undirected graph)
    newNode = createNode(src);
    newNode->next = graph->adjLists[dest];
    graph->adjLists[dest] = newNode;
}

// Function to perform DFS traversal
void DFS(Graph* graph, int vertex, int* visited) {
    visited[vertex] = 1;
    AdjListNode* temp = graph->adjLists[vertex];

    while (temp) {
        if (visited[temp->vertex] == 0) {
            DFS(graph, temp->vertex, visited);
        }
        temp = temp->next;
    }
}

// Function to count connected components
int countConnectedComponents(Graph* graph) {
    int* visited = (int*) malloc(graph->numVertices * sizeof(int));
    for (int i = 0; i < graph->numVertices; i++) {
        visited[i] = 0;
    }

    int count = 0;
    for (int i = 0; i < graph->numVertices; i++) {
        if (visited[i] == 0) {
            DFS(graph, i, visited);
            count++;
        }
    }

    free(visited);
    return count;
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);

        Graph* graph = createGraph(N);

        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            addEdge(graph, u, v);
        }

        printf("%d\n", countConnectedComponents(graph));

        // Free the graph
        for (int i = 0; i < N; i++) {
            AdjListNode* temp = graph->adjLists[i];
            while (temp) {
                AdjListNode* next = temp->next;
                free(temp);
                temp = next;
            }
        }
        free(graph->adjLists);
        free(graph);
    }

    return 0;
}

