int countConnectedComponents(vector<vector<int>>& graph, vector<bool>& visited, int vertex) {
    visited[vertex] = true;
    for (int neighbor : graph[vertex]) {
        if (!visited[neighbor]) {
            countConnectedComponents(graph, visited, neighbor);
        }
    }
